import React, {useEffect, useState} from 'react';
import { Switch } from '@lmb-it/kitsconcertomobile';
import KitsContainer from '../../helpers/FormContainer';
import type { IKitsInputSwitch } from '@lmb-it/kitsconcerto-types';
import { useSeparator } from "../../../factory";
import {useComponentDefaults, useResolvedStyle} from "@lmb-it/kitsconcerto/hooks";
import CheckboxButton from "../../controls/Checkbox/checkbox";

const KitsInputSwitch: React.FC<IKitsInputSwitch> = ({ ref, ...rawProps }) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Switch', rawProps);
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        label,
        helperText,
        errors,
        invalid,
        required,
        disabled,
        value,
        checked,
        onChange,
        displayAs,
        containerStyle,
        localProps,
        ...rest
    } = props;

    const isCheckbox = displayAs === 'checkbox';

    // Combine value and checked like in web version
    const incoming = typeof checked === 'boolean' ? checked : value;

    // Determine if component is controlled (both incoming and onChange exist)
    const isControlled = typeof incoming !== 'undefined' && typeof onChange === 'function';

    // For uncontrolled or partially controlled modes, maintain internal state
    const [internal, setInternal] = useState<boolean>(incoming ?? false);

    useEffect(() => {
        // If controlled, always reflect the incoming value
        if (isControlled) {
            setInternal(incoming as boolean);
        }
    }, [incoming, isControlled]);

    const handleToggle = (newVal: boolean) => {
        if (!isControlled) {
            setInternal(newVal);
        }
        // Always call onChange if provided
        onChange?.({ target: { value: newVal }, value: newVal });
    };

    const { nativeProps, cssProps } = useSeparator<any>({ ...rest, ...(localProps as any) });

    // Resolve display label text for checkbox mode
    const labelText = typeof label === 'string' ? label
        : typeof label === 'object' && label !== null && 'text' in (label as any) ? (label as any).text
        : undefined;

    const Element = isCheckbox
        ? <CheckboxButton
            item={{
                value: true,
                label: labelText ?? '',
                withBulbs: true,
                labelPosition: 'right',
            }}
            selected={!!internal}
            disabled={disabled}
            isInvalid={invalid}
            onToggle={() => handleToggle(!internal)}
        />
        : <Switch
            {...nativeProps}
            ref={ref as any}
            style={{...(resolvedRootStyle && Object.keys(resolvedRootStyle).length > 0 ? resolvedRootStyle : resolvedThemeStyle), ...(cssProps as any)}}
            value={internal}
            isDisabled={!!disabled}
            isInvalid={!!invalid}
            onToggle={handleToggle}
        />;

    return (
        <KitsContainer
            id={id}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={isCheckbox ? undefined : label}
            disabled={disabled}
            containerStyle={{borderRadius:0, overflow:"visible", ...containerStyle, borderWidth:0}}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputSwitch;
